import React, { useEffect, useMemo, useState } from 'react';
import { getProducts } from '../utils/api';
import { Product } from '../types/Product';
import ProductCard from './ProductCard';

interface ProductListProps {
  query: string;
}

const ProductList: React.FC<ProductListProps> = ({ query }) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(false);
  const [category, setCategory] = useState<string>('all');
  const [sort, setSort] = useState<string>('featured');

  useEffect(() => {
    let active = true;
    setLoading(true);
    getProducts().then((res) => {
      if (active) {
        setProducts(res);
        setLoading(false);
      }
    });
    return () => {
      active = false;
    };
  }, []);

  const categories = useMemo(() => {
    const set = new Set<string>();
    products.forEach((p) => set.add(p.category));
    return ['all', ...Array.from(set)];
  }, [products]);

  const filtered = useMemo(() => {
    let list = products.filter((p) => {
      const matchesQuery = query.trim().length === 0 || `${p.title} ${p.category} ${p.description}`.toLowerCase().includes(query.toLowerCase());
      const matchesCat = category === 'all' || p.category === category;
      return matchesQuery && matchesCat;
    });
    if (sort === 'price-asc') list = list.sort((a, b) => a.price - b.price);
    if (sort === 'price-desc') list = list.sort((a, b) => b.price - a.price);
    if (sort === 'rating') list = list.sort((a, b) => (b.rating || 0) - (a.rating || 0));
    if (sort === 'featured') list = list.sort((a, b) => Number(b.featured) - Number(a.featured));
    return list;
  }, [products, query, category, sort]);

  return (
    <div>
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-3 mb-4">
        <div className="flex items-center gap-2 flex-wrap">
          {categories.map((c) => (
            <button key={c} onClick={() => setCategory(c)} className={`px-3 py-1.5 rounded-lg border transition ${category === c ? 'bg-gray-900 text-white border-gray-900' : 'border-gray-200 hover:border-gray-300'}`}>
              {c[0].toUpperCase() + c.slice(1)}
            </button>
          ))}
        </div>
        <div className="flex items-center gap-2">
          <label className="text-sm text-gray-600">Sort by</label>
          <select value={sort} onChange={(e) => setSort(e.target.value)} className="rounded-lg border border-gray-300 px-3 py-2 outline-none focus:ring-2 ring-blue-600">
            <option value="featured">Featured</option>
            <option value="rating">Rating</option>
            <option value="price-asc">Price: Low to High</option>
            <option value="price-desc">Price: High to Low</option>
          </select>
        </div>
      </div>
      {loading && (
        <div className="grid md:grid-cols-3 gap-4">
          {Array.from({ length: 6 }).map((_, i) => (
            <div key={i} className="rounded-xl border border-gray-200 bg-white p-4 animate-pulse">
              <div className="h-48 bg-gray-200 rounded-lg"/>
              <div className="h-4 bg-gray-200 rounded w-1/2 mt-4"/>
              <div className="h-4 bg-gray-200 rounded w-1/3 mt-2"/>
              <div className="h-9 bg-gray-200 rounded mt-4"/>
            </div>
          ))}
        </div>
      )}
      {!loading && (
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.map((p) => (
            <ProductCard key={p.id} product={p} />
          ))}
          {filtered.length === 0 && (
            <div className="col-span-full text-center rounded-xl border border-gray-200 bg-white p-10">
              <div className="text-lg font-semibold">No products found</div>
              <div className="text-gray-600 mt-1">Try adjusting your search or filters.</div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ProductList;

