import React, { useState } from 'react';
import { Product } from '../types/Product';
import { useCart } from '../utils/hooks';

interface ProductCardProps {
  product: Product;
}

const Rating: React.FC<{ value: number } > = ({ value }) => {
  const full = Math.floor(value);
  const half = value - full >= 0.5;
  return (
    <div className="flex items-center gap-0.5 text-yellow-500 text-sm" aria-label={`Rated ${value} out of 5`}>
      {Array.from({ length: 5 }).map((_, i) => {
        const isFull = i < full;
        const isHalf = i === full && half;
        return (
          <span key={i}>{isFull ? '★' : isHalf ? '☆' : '☆'}</span>
        );
      })}
      <span className="text-gray-600 ml-1">{value.toFixed(1)}</span>
    </div>
  );
};

const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const { addItem } = useCart();
  const [adding, setAdding] = useState(false);
  const [qty, setQty] = useState(1);
  const inc = () => setQty((q) => Math.min(q + 1, 9));
  const dec = () => setQty((q) => Math.max(1, q - 1));

  const handleAdd = () => {
    setAdding(true);
    setTimeout(() => {
      addItem(product, qty);
      setAdding(false);
      setQty(1);
    }, 250);
  };

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-3 shadow-md hover:shadow-lg transition flex flex-col">
      <div className="relative">
        <img src={product.image} alt={product.title} className="w-full h-56 object-cover rounded-lg" />
        {product.featured && (
          <span className="absolute top-2 left-2 text-xs bg-white/90 px-2 py-1 rounded-full shadow">Featured</span>
        )}
        <span className="absolute top-2 right-2 text-xs bg-gray-900 text-white px-2 py-1 rounded-full">{product.category}</span>
      </div>
      <div className="flex-1 pt-3">
        <div className="flex items-start justify-between gap-2">
          <h3 className="font-semibold text-gray-900 leading-snug">{product.title}</h3>
          <div className="font-bold">${product.price.toFixed(2)}</div>
        </div>
        <p className="text-sm text-gray-600 mt-1 line-clamp-2">{product.description}</p>
        <div className="mt-2"><Rating value={product.rating || 4.5} /></div>
      </div>
      <div className="mt-3 flex items-center justify-between gap-2">
        <div className="flex items-center gap-2">
          <button onClick={() => dec()} className="w-8 h-8 rounded-lg border border-gray-300 hover:bg-gray-50">−</button>
          <div className="w-8 h-8 rounded-lg border border-gray-200 flex items-center justify-center text-sm font-medium">{qty}</div>
          <button onClick={() => inc()} className="w-8 h-8 rounded-lg border border-gray-300 hover:bg-gray-50">+</button>
        </div>
        <button disabled={adding} onClick={() => handleAdd()} className={`px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition ${adding ? 'opacity-70' : ''}`}>
          {adding ? 'Adding…' : 'Add to cart'}
        </button>
      </div>
    </div>
  );
};

export default ProductCard;

