import React, { useMemo, useState } from 'react';
import { useCart } from '../utils/hooks';

interface CheckoutProps {
  onBack: () => void;
}

const Input: React.FC<React.InputHTMLAttributes<HTMLInputElement> & { label: string } > = ({ label, ...props }) => {
  return (
    <label className="block">
      <div className="text-sm font-medium mb-1">{label}</div>
      <input {...props} className={`w-full rounded-lg border border-gray-300 px-3 py-2 outline-none focus:ring-2 ring-blue-600 ${props.className || ''}`} />
    </label>
  );
};

const Checkout: React.FC<CheckoutProps> = ({ onBack }) => {
  const { items, total, clear } = useCart();
  const [placing, setPlacing] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [address, setAddress] = useState('');
  const [city, setCity] = useState('');
  const [zip, setZip] = useState('');
  const [card, setCard] = useState('');

  const shipping = useMemo(() => (total >= 100 || total === 0 ? 0 : 7.95), [total]);
  const grand = useMemo(() => total + shipping, [total, shipping]);

  const valid = useMemo(() => {
    return email.includes('@') && name.length > 1 && address.length > 5 && city.length > 1 && zip.length > 3 && card.replaceAll(' ', '').length >= 12 && items.length > 0;
  }, [email, name, address, city, zip, card, items.length]);

  const placeOrder = () => {
    if (!valid) return;
    setPlacing(true);
    setTimeout(() => {
      setPlacing(false);
      setSuccess(true);
      clear();
    }, 900);
  };

  if (success) {
    return (
      <div className="rounded-xl border border-gray-200 bg-white p-8 shadow-md text-center">
        <div className="text-4xl mb-2">🎉</div>
        <div className="text-2xl font-extrabold">Order Confirmed</div>
        <div className="text-gray-600 mt-2">We've emailed your receipt to {email}. Your items will ship soon.</div>
        <div className="mt-6 flex justify-center">
          <button onClick={() => onBack()} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Continue Shopping</button>
        </div>
      </div>
    );
  }

  return (
    <div className="grid lg:grid-cols-3 gap-6">
      <div className="lg:col-span-2 rounded-xl border border-gray-200 bg-white p-6 shadow-md">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-bold">Checkout</h2>
          <button onClick={() => onBack()} className="px-3 py-1.5 rounded-lg bg-gray-100 hover:bg-gray-200 transition">Back</button>
        </div>
        <div className="grid md:grid-cols-2 gap-4">
          <Input label="Email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="you@example.com" />
          <Input label="Full Name" value={name} onChange={(e) => setName(e.target.value)} placeholder="Jane Doe" />
          <Input label="Address" value={address} onChange={(e) => setAddress(e.target.value)} placeholder="123 Market St" className="md:col-span-2" />
          <Input label="City" value={city} onChange={(e) => setCity(e.target.value)} placeholder="San Francisco" />
          <Input label="ZIP / Postal" value={zip} onChange={(e) => setZip(e.target.value)} placeholder="94103" />
          <Input label="Card Number" value={card} onChange={(e) => setCard(e.target.value)} placeholder="4242 4242 4242 4242" className="md:col-span-2" />
        </div>
        <div className="mt-6 flex justify-end">
          <button disabled={!valid || placing} onClick={() => placeOrder()} className={`px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition ${!valid || placing ? 'opacity-60' : ''}`}>
            {placing ? 'Placing order…' : `Pay $${grand.toFixed(2)}`}
          </button>
        </div>
      </div>
      <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-md h-fit">
        <h3 className="font-semibold mb-3">Order summary</h3>
        <div className="space-y-3 max-h-72 overflow-auto pr-1">
          {items.map((it) => (
            <div key={it.product.id} className="flex items-center gap-3">
              <img src={it.product.image} alt={it.product.title} className="w-14 h-14 rounded-lg object-cover" />
              <div className="flex-1">
                <div className="text-sm font-medium leading-tight">{it.product.title}</div>
                <div className="text-xs text-gray-600">Qty {it.quantity}</div>
              </div>
              <div className="text-sm font-semibold">${(it.product.price * it.quantity).toFixed(2)}</div>
            </div>
          ))}
          {items.length === 0 && (
            <div className="text-sm text-gray-600">Your cart is empty.</div>
          )}
        </div>
        <div className="border-t border-gray-200 mt-4 pt-3 space-y-1 text-sm">
          <div className="flex items-center justify-between"><span className="text-gray-600">Subtotal</span><span className="font-semibold">${total.toFixed(2)}</span></div>
          <div className="flex items-center justify-between"><span className="text-gray-600">Shipping</span><span className="font-semibold">{shipping === 0 ? 'Free' : `$${shipping.toFixed(2)}`}</span></div>
          <div className="flex items-center justify-between text-base pt-1"><span className="font-semibold">Total</span><span className="font-extrabold">${grand.toFixed(2)}</span></div>
        </div>
      </div>
    </div>
  );
};

