import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { CartContextType, CartItem } from '../types/Cart';
import { Product } from '../types/Product';

export const useLocalStorage = <T,>(key: string, initial: T) => {
  const [state, setState] = useState<T>(() => {
    try {
      const raw = localStorage.getItem(key);
      return raw ? (JSON.parse(raw) as T) : initial;
    } catch {
      return initial;
    }
  });
  useEffect(() => {
    try {
      localStorage.setItem(key, JSON.stringify(state));
    } catch {}
  }, [key, state]);
  return [state, setState] as const;
};

const CartContext = createContext<CartContextType | null>(null);

export const CartProvider: React.FC<{ children: React.ReactNode } > = ({ children }) => {
  const [items, setItems] = useLocalStorage<CartItem[]>('cart-v1', []);

  const addItem = (product: Product, quantity = 1) => {
    setItems((prev) => {
      const idx = prev.findIndex((p) => p.product.id === product.id);
      if (idx >= 0) {
        const copy = [...prev];
        copy[idx] = { ...copy[idx], quantity: copy[idx].quantity + quantity };
        return copy;
      }
      return [...prev, { product, quantity }];
    });
  };

  const removeItem = (productId: string) => {
    setItems((prev) => prev.filter((it) => it.product.id !== productId));
  };

  const updateQuantity = (productId: string, quantity: number) => {
    setItems((prev) => prev.map((it) => (it.product.id === productId ? { ...it, quantity: Math.max(1, quantity) } : it)));
  };

  const clear = () => setItems([]);

  const total = useMemo(() => items.reduce((sum, it) => sum + it.product.price * it.quantity, 0), [items]);
  const count = useMemo(() => items.reduce((sum, it) => sum + it.quantity, 0), [items]);

  const value: CartContextType = {
    items,
    addItem,
    removeItem,
    updateQuantity,
    clear,
    total,
    count
  };

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
};

export const useCart = (): CartContextType => {
  const ctx = useContext(CartContext);
  if (!ctx) throw new Error('useCart must be used within CartProvider');
  return ctx;
};

